3757	//
3758	// zrbtdrc_darken_svg is a pure function of the rendered bytes, so its
3759	// correctness is proven here without charging a crucible — distinct from the
3760	// crucible case, which proves the PlantUML server renders well-formed SVG.
3761	
3762	#[cfg(test)]
3763	mod rbtdrc_tests {
3764	    use super::*;
3765	
3766	    #[test]
3767	    fn zrbtdrc_darken_svg_maps_the_surveyed_palette() {
3768	        let light = concat!(
3769	            r##"<svg style="width:10px;height:10px;background:#FFFFFF;">"##,
3770	            r##"<text fill="#000000">x</text>"##,
3771	            r##"<line style="stroke:#181818;"/>"##,
3772	            r##"<rect fill="#E2E2F0"/><rect fill="#FEFFDD"/><rect fill="#EEEEEE"/></svg>"##,
3773	        );
3774	        let dark = zrbtdrc_darken_svg(light);
3775	
3776	        // Page background dropped to transparent.
3777	        assert!(dark.contains("background:transparent;"));
3778	        assert!(!dark.contains("background:#FFFFFF;"));
3779	
3780	        // Every surveyed light color is gone, replaced by its dark mapping —
3781	        // and the map reaches colors inside style="..." strings, not just
3782	        // fill="..."/stroke="..." attributes (blunt hex substitution).
3783	        assert!(!dark.contains("#000000") && dark.contains("#E6E6E6"));
3784	        assert!(!dark.contains("#181818") && dark.contains("#9DA5B4"));
3785	        assert!(!dark.contains("#E2E2F0") && dark.contains("#3B3B54"));
3786	        assert!(!dark.contains("#FEFFDD") && dark.contains("#48421F"));
3787	        assert!(!dark.contains("#EEEEEE") && dark.contains("#2B2B2B"));
3788	    }
3789	
3790	    #[test]
3791	    fn zrbtdrc_darken_svg_passes_unsurveyed_colors_through() {
3792	        // A color outside the surveyed palette is left untouched — the membrane
3793	        // is characterized, not a guess-everything recolor.
3794	        let light = r##"<rect fill="#AB12CD"/>"##;
3795	        assert_eq!(zrbtdrc_darken_svg(light), light);
3796	    }
3797	}
